alter table public.generations add column if not exists is_public boolean not null default false, add column if not exists share_token text unique; create index if not exists generations_share_token_idx on public.generations(share_token) where share_token is not null; create index if not exists generations_is_public_idx on public.generations(is_public) where is_public = true; create table if not exists public.email_log (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade, to_email text not null, template text not null, status text not null default 'sent', error text, sent_at timestamptz not null default now()); grant select, insert on public.email_log to authenticated; grant all on public.email_log to service_role; alter table public.email_log enable row level security; drop policy if exists "users read own email log" on public.email_log; create policy "users read own email log" on public.email_log for select to authenticated using (auth.uid() = user_id); drop policy if exists "service writes email log" on public.email_log; create policy "service writes email log" on public.email_log for insert to service_role with check (true);